import { useState, useEffect } from "react";
import { WalletProvider } from "./context/WalletContext";
import { AppProvider, useApp } from "./context/AppContext";
import Navbar from "./components/layout/Navbar";
import BottomNav from "./components/layout/BottomNav";
import WalletPrompt from "./components/layout/WalletPrompt";
import HomePage from "./pages/Home";
import ExplorePage from "./pages/Explore";
import EventDetailsPage from "./pages/EventDetails";
import MyTicketsPage from "./pages/MyTickets";
import DashboardPage from "./pages/Dashboard";
import CreateEventPage from "./pages/CreateEvent";

function AppInner() {
  const { events, refreshEvents, refreshTickets, refreshOrgEvents } = useApp();
  const [page,     setPage]    = useState("home");
  const [selEv,    setSelEv]   = useState(null);
  const [isMobile, setMobile]  = useState(window.innerWidth < 768);

  useEffect(() => {
    const onR = () => setMobile(window.innerWidth < 768);
    window.addEventListener("resize", onR);
    return () => window.removeEventListener("resize", onR);
  }, []);

  // Hash-based deep links: #/event/<slug-or-id>
  useEffect(() => {
    const hash = window.location.hash;
    if (hash.startsWith("#/event/")) {
      const token = hash.replace("#/event/", "");
      // Try to match after events load
      const found = events.find(e => e.slug === token || String(e.id) === token);
      if (found) { setSelEv(found); setPage("event"); }
    }
  }, [events]);

  const nav = pg => { setPage(pg); window.scrollTo({ top: 0, behavior: "smooth" }); };

  const handleEventCreated = async () => {
    await refreshEvents();
    nav("dashboard");
  };

  const handleTicketBought = async () => {
    await refreshTickets();
  };

  const renderPage = () => {
    switch (page) {
      case "home":      return <HomePage setPage={nav} setSelectedEvent={e => { setSelEv(e); nav("event"); }} />;
      case "explore":   return <ExplorePage setPage={nav} setSelectedEvent={e => { setSelEv(e); nav("event"); }} />;
      case "event":     return selEv ? <EventDetailsPage event={selEv} setPage={nav} onTicketBought={handleTicketBought} /> : <HomePage setPage={nav} setSelectedEvent={e => { setSelEv(e); nav("event"); }} />;
      case "tickets":   return <MyTicketsPage />;
      case "dashboard": return <DashboardPage setPage={nav} />;
      case "create":    return <CreateEventPage setPage={nav} onCreated={handleEventCreated} />;
      default:          return <HomePage setPage={nav} setSelectedEvent={e => { setSelEv(e); nav("event"); }} />;
    }
  };

  return (
    <div className="mw">
      <Navbar page={page} setPage={nav} isMobile={isMobile} />
      <main style={{ paddingBottom: isMobile ? 68 : 0 }}>{renderPage()}</main>
      {isMobile && <BottomNav page={page} setPage={nav} />}
      <WalletPrompt />
    </div>
  );
}

export default function App() {
  return (
    <WalletProvider>
      <AppProvider>
        <AppInner />
      </AppProvider>
    </WalletProvider>
  );
}
